input.command:
cd /workspace/rollouts/employment-labor_draft-markup-of-settlement-agreement && perl -MJSON::PP -e '
local $/; open(F,"transcript.jsonl"); my $raw=<F>; close F;
my @lines=grep {length} split /\n/,$raw;
my $i=0;
for my $l (@lines){
  $i++;
  my $e=eval{decode_json($l)}; next unless $e;
  my $role=$e->{role}//"";
  if($role eq "assistant"){
    for my $c (@{$e->{content}//[]}){
      next unless ref $c eq "HASH";
      if($c->{type} eq "text"){
        my $t=$c->{text}; $t=~s/\n/ /g; $t=substr($t,0,180);
        print "$i ASST-TEXT: $t\n";
      } elsif($c->{type} eq "tool_use"){
        my $n=$c->{name}//"";
        my $in=$c->{input}//{};
        my $fp=$in->{file_path}//$in->{path}//"";
        my $cmd=substr($in->{command}//"",0,100);
        print "$i TOOL $n | $fp | $cmd\n";
      }
    }
  }
}
' 2>&1 | head -120
